import{_ as a,o as e,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Random Image API والمعرض العام","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/random-image-api-and-public-gallery.md","filePath":"ar-SA/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"ar-SA/Other/random-image-api-and-public-gallery.md"};function i(l,t,n,c,s,p){return e(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="random-image-api-والمعرض-العام" tabindex="-1">Random Image API والمعرض العام <a class="header-anchor" href="#random-image-api-والمعرض-العام" aria-label="Permalink to &quot;Random Image API والمعرض العام&quot;">​</a></h1><p>تُضبط الميزتان من:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>يعيد Random Image API ملفًا عشوائيًا من مجلدات محددة. يفيد لخلفيات المواقع، أو تدوير الصور الرمزية، أو استدعاء صورة عشوائية من صفحات خارجية.</p><p>بعد تفعيله استخدم:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="إعدادات-random-image-api" tabindex="-1">إعدادات Random Image API <a class="header-anchor" href="#إعدادات-random-image-api" aria-label="Permalink to &quot;إعدادات Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الغرض</th></tr></thead><tbody><tr><td>Enable</td><td>تشغيل أو إيقاف endpoint <code>/random</code>. عند الإيقاف يُمنع الوصول.</td></tr><tr><td>Directories</td><td>يحدد المجلدات التي يمكن للواجهة العشوائية استخدامها. المجلدات غير المدرجة لا يمكن استخدامها.</td></tr><tr><td>Call demo</td><td>ينشئ روابط random API يمكنك نسخها مباشرة.</td></tr></tbody></table><p>يمكن اختيار عدة مجلدات. مثلًا، إذا سمحت فقط بـ <code>/landscape/</code> و <code>/portrait/</code> فلن يختار random API إلا من هذين المجلدين ومجلداتهما الفرعية.</p><h2 id="معاملات-random-image-api" tabindex="-1">معاملات Random Image API <a class="header-anchor" href="#معاملات-random-image-api" aria-label="Permalink to &quot;معاملات Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المعامل</th><th>مثال</th><th>الغرض</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>يحدد المجلد العشوائي.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>يحدد نوع الوسائط. استخدم <code>image</code> أو <code>video</code> أو <code>audio</code> أو تركيبات مفصولة بفواصل.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>يفلتر اتجاه الصورة. استخدم <code>portrait</code> أو <code>landscape</code> أو <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>صيغة الرد. فارغ يعني redirect، و <code>url</code> يعيد رابطًا نصيًا، و <code>json</code> يعيد JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>مع <code>type=url</code> يعيد رابطًا كاملًا.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>يفلتر حسب age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>يعيد فقط الملفات التي تحتوي هذه tags.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>يستبعد الملفات التي تحتوي هذه tags.</td></tr></tbody></table><h2 id="صيغ-الرد" tabindex="-1">صيغ الرد <a class="header-anchor" href="#صيغ-الرد" aria-label="Permalink to &quot;صيغ الرد&quot;">​</a></h2><p>دون <code>type</code>، يحوّل API مباشرة إلى رابط الملف العشوائي.</p><p>مع <code>type=url</code> يعيد رابطًا نصيًا.</p><p>مع <code>type=json</code> يعيد معلومات الملف، بما في ذلك file URL و file ID و file name و file type و tags و rating و metadata المرتبطة.</p><h2 id="قواعد-الوصول" tabindex="-1">قواعد الوصول <a class="header-anchor" href="#قواعد-الوصول" aria-label="Permalink to &quot;قواعد الوصول&quot;">​</a></h2><p>يلتزم Random Image API بقواعد public access:</p><table tabindex="0"><thead><tr><th>القاعدة</th><th>التأثير</th></tr></thead><tbody><tr><td>Directory restriction</td><td>لا تُختار إلا الملفات داخل المجلدات المسموحة.</td></tr><tr><td>Blocklist</td><td>تُستبعد blocklisted files من مجموعة الاختيار العشوائي.</td></tr><tr><td>Allowlist mode</td><td>عند تفعيله لا تعاد إلا الملفات المسموح بها للوصول العام.</td></tr><tr><td>Age rating</td><td>تُفلتر محتويات R12 و R16 و R18 وما شابه حسب access mode الحالي.</td></tr></tbody></table><p>إذا لم يوجد ملف مطابق بعد التصفية، يعيد API نتيجة بعدم وجود تطابق.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>يخزّن Random Image API مجموعات المرشحين للمجلدات في الكاش لتحسين السرعة.</p><p>بعد تغيّر الملفات، يحدّث ImgBed إصدار كاش المجلد، ثم تعيد الطلبات اللاحقة بناء مجموعة المرشحين. تُخزن المجلدات الفارغة مؤقتًا لفترة قصيرة لتجنب الاستعلامات المتكررة.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>يوفر public gallery صفحة تصفح عامة للقراءة فقط للمجلدات التي تسمح للزوار برؤيتها.</p><p>بعد تفعيلها يمكن للزوار فتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="إعدادات-public-gallery" tabindex="-1">إعدادات Public Gallery <a class="header-anchor" href="#إعدادات-public-gallery" aria-label="Permalink to &quot;إعدادات Public Gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الغرض</th></tr></thead><tbody><tr><td>Enable</td><td>تشغيل أو إيقاف public gallery. عند الإيقاف لا يستطيع الزوار تصفحها.</td></tr><tr><td>Image loading mode</td><td>يحدد هل تستخدم المعاينات الصور الأصلية أو thumbnails.</td></tr><tr><td>Open directories</td><td>يحدد المجلدات التي يمكن للزوار الوصول إليها.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الوضع</th><th>الغرض</th></tr></thead><tbody><tr><td>Original</td><td>صفحة الزائر تحمّل الملفات الأصلية مباشرة.</td></tr><tr><td>Thumbnail</td><td>صفحة الزائر تفضّل thumbnails لتحميل أسرع.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>تحدد Open directories ما يستطيع الزوار رؤيته.</p><p>مثال:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>يمكن للزوار بعدها الوصول إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>يمكن أيضًا فتح مجلدات فرعية مثل <code>/2026/lucky/</code>. يُمنع الزوار من المجلدات غير المفتوحة.</p><h2 id="ميزات-public-gallery" tabindex="-1">ميزات Public Gallery <a class="header-anchor" href="#ميزات-public-gallery" aria-label="Permalink to &quot;ميزات Public Gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الميزة</th><th>الوصف</th></tr></thead><tbody><tr><td>Browse directories</td><td>عرض الملفات والمجلدات الفرعية داخل المجلدات المفتوحة.</td></tr><tr><td>Search</td><td>البحث حسب file name أو file ID أو tags.</td></tr><tr><td>Type filter</td><td>تصفية الصور أو الفيديو أو الصوت أو الملفات الأخرى.</td></tr><tr><td>Tag filter</td><td>تضمين أو استبعاد tags محددة.</td></tr><tr><td>Orientation filter</td><td>تصفية صور landscape أو portrait.</td></tr><tr><td>Time filter</td><td>التصفية حسب نطاق وقت الرفع.</td></tr><tr><td>Extension filter</td><td>التصفية حسب file extension.</td></tr><tr><td>Copy link</td><td>نسخ روابط الوصول للملفات.</td></tr><tr><td>Media preview</td><td>عرض أو تشغيل الصور والفيديو والصوت في صفحة الزائر.</td></tr></tbody></table><h2 id="قواعد-وصول-public-gallery" tabindex="-1">قواعد وصول Public Gallery <a class="header-anchor" href="#قواعد-وصول-public-gallery" aria-label="Permalink to &quot;قواعد وصول Public Gallery&quot;">​</a></h2><p>تلتزم public gallery أيضًا بقواعد public access:</p><table tabindex="0"><thead><tr><th>القاعدة</th><th>التأثير</th></tr></thead><tbody><tr><td>Open directories</td><td>لا تظهر إلا المجلدات المسموحة.</td></tr><tr><td>Access mode</td><td>يُفلتر المحتوى حسب age-rating access mode الحالي.</td></tr><tr><td>Allowlist mode</td><td>عند تفعيله لا تظهر إلا الملفات المسموح بها للوصول العام.</td></tr><tr><td>Blocklist</td><td>تُخفى blocklisted files.</td></tr></tbody></table>`,43)])])}const m=a(r,[["render",i]]);export{b as __pageData,m as default};
